@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    /* Mobile toolbar: horizontal scroll with visible thin scrollbar */
    .toolbar {
        flex-wrap: nowrap;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        scrollbar-width: thin;
        min-width: 0;
    }
    .toolbar .group,
    .toolbar .toolbar-bttns,
    .toolbar .is-active {
        flex-shrink: 0;
    }
    .toolbar::-webkit-scrollbar {
        height: 3px;
    }
    .toolbar::-webkit-scrollbar-thumb {
        background: var(--editor-border);
        border-radius: 3px;
    }
    .toolbar-wrapper {
        position: relative;
    }
    .toolbar-wrapper::after {
        content: '';
        position: absolute;
        top: 0;
        right: 0;
        bottom: 0;
        width: 24px;
        background: linear-gradient(to right, transparent, var(--editor-bg, var(--bg-elevated)));
        pointer-events: none;
        z-index: 6;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.55rem;
        min-width: 36px;
        min-height: 36px;
    }

