 61→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 62→    const [editor] = useLexicalComposerContext();
 63→    const [editorState, setEditorState] = useState(null);
 64→    const [hasContent, setHasContent] = useState(false);
 65→    const [isSending, setIsSending] = useState(false);
 66→
 67→    // Draft state
 68→    const draftIdRef = useRef(draftId);
 69→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 70→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 71→    const [hasChanges, setHasChanges] = useState(false);
 72→    const saveTimerRef = useRef(null);
 73→    const [, forceUpdate] = useState(0);
 74→
 75→    // Expose saveTimerRef to parent so it can cancel pending auto-saves
 76→    useEffect(() => {
 77→        if (editorStateRef) {
 78→            editorStateRef.current.saveTimerRef = saveTimerRef;
 79→        }
 80→    }, [editorStateRef]);
 81→
 82→    const {session, user} = useAuth();
 83→
 84→    const queryClient = useQueryClient();
 85→    const userId = user?.userData?.[0]?.id || null;
 86→
 87→    // Keep draftIdRef in sync
 88→    useEffect(() => {
 89→        draftIdRef.current = draftId;
 90→    }, [draftId]);
 91→
 92→    // Tick the "saved X ago" display every 30s
 93→    useEffect(() => {
 94→        if (!lastSavedAt) return;
 95→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 96→        return () => clearInterval(interval);
 97→    }, [lastSavedAt]);
 98→
 99→    const invalidateCreatedJournalQueries = useCallback(async() => {
100→        const invalidations = [
101→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
102→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
103→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
104→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
105→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
106→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
107→        ];
108→
109→        if(userId){
110→            invalidations.push(
111→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
112→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
113→            );
114→        }
115→
116→        await Promise.allSettled(invalidations);
117→    }, [queryClient, userId]);
118→
119→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
120→        if (!editorState || !session?.access_token) return;
121→        if (showFeedback) setSaveStatus('saving');
122→
123→        try {
124→            const result = await saveDraft(session.access_token, {
125→                content: editorState,
126→                title: title || '',
127→                draftId: draftIdRef.current || null,
128→                prompt_id: promptId || null,
129→            });
130→
131→            if (result?.id && !draftIdRef.current) {
132→                draftIdRef.current = result.id;
133→                if (onDraftIdCreated) onDraftIdCreated(result.id);
134→            }
135→
136→            setHasChanges(false);
137→            setSaveStatus('saved');
138→            setLastSavedAt(new Date());
139→            if (editorStateRef) {
140→                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
141→            }
142→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
143→        } catch (error) {
144→            console.error('Failed to save draft:', error);
145→            setSaveStatus('unsaved');
146→        }
147→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
148→
149→    // Auto-save every 30 seconds when there are changes
150→    useEffect(() => {
151→        if (!hasChanges || !editorState) return;
152→
153→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
154→        saveTimerRef.current = setTimeout(() => {
155→            handleSaveDraft(false);
156→        }, 30000);
157→
158→        return () => {
159→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
160→        };
161→    }, [editorState, hasChanges, handleSaveDraft]);
162→
163→    const handleClickPublish = async(e, title) => {
164→        e.stopPropagation();
165→        setIsSending(true);
166→
167→        try {
168→            // If we have a draft, publish it
169→            if (draftIdRef.current) {
170→                // Save latest content first
171→                await saveDraft(session.access_token, {
172→                    content: editorState,
173→                    title: title || '',
174→                    draftId: draftIdRef.current,
175→                });
176→
177→                await publishDraft(session.access_token, draftIdRef.current);
178→            } else {
179→                // Direct publish (no draft exists) — use existing save-journal flow
180→                const formdata = new FormData();
181→                if(title && editorState){
182→                    formdata.append('title', title);
183→                    formdata.append('content', editorState);
184→                }
185→                if(promptId){
186→                    formdata.append('prompt_id', promptId);
187→                }
188→                await saveJournal(session?.access_token, formdata);
189→            }
190→
191→            await invalidateCreatedJournalQueries();
192→            setHasContent(false);
193→            onCloseOnSave();
194→            addUploadImagesPath([]);
195→        } catch (error) {
196→            console.error("Error publishing journal:", error);
197→        } finally {
198→            setIsSending(false);
199→        }
200→    }
201→
202→    const onchange = useCallback((state) => {
203→        const jsonb = JSON.stringify(state.toJSON());
204→        setEditorState(jsonb)
205→        setHasChanges(true);
206→        if (saveStatus === 'saved') setSaveStatus('unsaved');
207→
208→        state.read(() => {
209→            const root = $getRoot();
210→
211→            const children = root.getChildren();
212→
213→            const hasEnoughParagraphNodes = children.length > 1
214→            const hasParargraphSize = children[0]?.__size > 0
215→
216→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
217→            setHasContent(hasContent);
218→
219→            // Calculate word count
220→            const text = root.getTextContent().trim();
221→            const words = text ? text.split(/\s+/).length : 0;
222→            setWordCount(words);
223→
224→            // Expose state to parent via ref
225→            if (editorStateRef) {
226→                editorStateRef.current = { ...editorStateRef.current, hasChanges: true, hasContent, editorState: jsonb, title };
227→            }
228→        })
229→    }, [setWordCount, saveStatus])
230→
231→    const renderSaveStatus = () => {
232→        if (!saveStatus) return null;
233→
234→        let statusText = '';
235→        let statusClass = 'editor-save-status';
236→
237→        switch (saveStatus) {
238→            case 'saving':
239→                statusText = 'Saving...';
240→                statusClass += ' editor-save-status--saving';
241→                break;
242→            case 'saved':
243→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
244→                statusClass += ' editor-save-status--saved';
245→                break;
246→            case 'unsaved':
247→                statusText = 'Unsaved changes';
248→                statusClass += ' editor-save-status--unsaved';
249→                break;
250→            default:
251→                return null;
